class TextEditor {
    StringBuilder text;
    int cursor;

    public TextEditor() {
        text = new StringBuilder();
        cursor = 0;
    }

    public void addText(String newText) {
        text.insert(cursor, newText);
        cursor += newText.length();
    }

    public int deleteText(int k) {
        int deleted = Math.min(k, cursor);
        text.delete(cursor - deleted, cursor);
        cursor -= deleted;
        return deleted;
    }

    public String cursorLeft(int k) {
        cursor = Math.max(0, cursor - k);
        int len = Math.min(10, cursor);
        return text.substring(cursor - len, cursor);
    }

    public String cursorRight(int k) {
        cursor = Math.min(text.length(), cursor + k);
        int len = Math.min(10, cursor);
        return text.substring(cursor - len, cursor);
    }
}
```
